/* Cards WITH images get horizontal layout */
.card:has(img) {
  display: grid;
  grid-template-columns: 200px 1fr;
}

/* Cards WITHOUT images stay vertical */
.card {
  display: flex;
  flex-direction: column;
}

/* Label glows when its sibling input has focus */
label:has(+ input:focus) {
  color: #2563eb;
  font-weight: 700;
}

/* Form group gets a border when active */
.form-group:has(input:focus) {
  border-color: #2563eb;
  box-shadow: 0 0 0 3px rgba(37,99,235,0.1);
}

/* Hide sections with no content */
section:not(:has(*)) {
  display: none;
}

/* Gray out nav items with no dropdown */
.nav-item:not(:has(.dropdown)) {
  pointer-events: none;
  opacity: 0.4;
}

/* Dim the button if ANY field is invalid */
form:has(:invalid) button[type="submit"] {
  opacity: 0.4;
  cursor: not-allowed;
}

/* Red border on the form itself */
form:has(:invalid) {
  border: 2px solid #ef4444;
}

/* The checkbox toggles dark mode */
body:has(#dark-toggle:checked) {
  --bg: #0a0a0a;
  --text: #e0e0e0;
  --card: #1a1a1a;
}

/* No JavaScript. No localStorage.
   Just CSS reading a checkbox state. */
